      // Build chronological conversation history context for Gemini
      let formattedPrompt = "Historial del chat de atención al cliente:\n\n";
      if (Array.isArray(history) && history.length > 0) {
        history.forEach((msg: any) => {
          const senderLabel = msg.sender === 'client' ? 'Cliente' : 'Asistente IA';
          formattedPrompt += `[${senderLabel}]: ${msg.text}\n`;
