    21→    .replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
    22→}
    23→
    24→function b64urlDecode(s: string): Uint8Array {
    25→  const padded = s.replace(/-/g, "+").replace(/_/g, "/").padEnd(Math.ceil(s.length / 4) * 4, "=");
    26→  return Uint8Array.from(atob(padded), c => c.charCodeAt(0));
    27→}
