    29→async function getKey(secret: string, usage: KeyUsage[]): Promise<CryptoKey> {
    30→  return crypto.subtle.importKey("raw", new TextEncoder().encode(secret), { name: "HMAC", hash: "SHA-256" }, false, usage);
    31→}
    32→
    33→export async function signJWT(payload: Omit<AdminTokenPayload, "exp">): Promise<string> {
    34→  const exp = Math.floor(Date.now() / 1000) + JWT_EXPIRY_HOURS * 3600;
    35→  const header = b64url(new TextEncoder().encode(JSON.stringify({ alg: "HS256", typ: "JWT" })));
    36→  const body   = b64url(new TextEncoder().encode(JSON.stringify({ ...payload, exp })));
    37→  const key    = await getKey(JWT_SECRET, ["sign"]);
    38→  const sig    = b64url(await crypto.subtle.sign("HMAC", key, new TextEncoder().encode(`${header}.${body}`)));
    39→  return `${header}.${body}.${sig}`;
    40→}
