    45→    if (!header || !body || !sig) return null;
    46→    const key      = await getKey(JWT_SECRET, ["verify"]);
    47→    const valid    = await crypto.subtle.verify("HMAC", key, b64urlDecode(sig), new TextEncoder().encode(`${header}.${body}`));
    48→    if (!valid) return null;
    49→    const payload: AdminTokenPayload = JSON.parse(new TextDecoder().decode(b64urlDecode(body)));
    50→    if (payload.exp < Math.floor(Date.now() / 1000)) return null;
    51→    return payload;
    52→  } catch { return null; }
    53→}
