    48→ * si no, usa DEFAULT_SYSTEM_PROMPT.
    49→ * En ambos casos interpola las variables disponibles.
    50→ */
    51→export function buildPrompt(
    52→  vars: PromptVars,
    53→  systemPromptOverride?: string | null,
    54→): string {
    55→  const base = systemPromptOverride?.trim() || DEFAULT_SYSTEM_PROMPT;
    56→
    57→  const replacements: Record<string, string> = {
    58→    '{storeName}':          vars.storeName,
    59→    '{language}':           vars.language,
    60→    '{toneInstruction}':    TONE_MAP[vars.sentiment],
    61→    '{orderCount}':         String(vars.context.orderCount),
    62→    '{totalSpent}':         vars.context.totalSpent.toFixed(2),
