   124→  private classifyIntent(message: string): QueryIntent {
   125→    const m = message.toLowerCase();
   126→    if (/\b(pedido|orden|order|estado|seguimiento|track)\b/.test(m))  return 'order_status';
   127→    if (/\b(devoluci[oó]n|reembolso|refund|cancelar|cancel)\b/.test(m)) return 'refund_request';
   128→    if (/\b(comprar|agregar|carrito|checkout|quiero|necesito)\b/.test(m)) return 'place_order';
   129→    if (/\b(recomendar|sugerir|qu[eé] me recomiendas|opciones)\b/.test(m)) return 'recommendation';
   130→    if (/\b(producto|precio|stock|disponible|descripci[oó]n)\b/.test(m)) return 'product_inquiry';
