   134→  private analyzeSentiment(message: string): Sentiment {
   135→    const m = message.toLowerCase();
   136→    const positive = ['gracias', 'excelente', 'perfecto', 'genial', 'bien', 'bueno', 'feliz'];
   137→    const negative = ['mal', 'problema', 'error', 'enojado', 'molesto', 'terrible', 'horrible', 'pésimo'];
   138→    const posScore = positive.filter(w => m.includes(w)).length;
   139→    const negScore = negative.filter(w => m.includes(w)).length;
   140→    if (posScore > negScore) return 'positive';
   141→    if (negScore > posScore) return 'negative';
   142→    return 'neutral';
   143→  }
